import java.io.*;
import java.net.*;

public class TCPServer {
 public static void main(String[] args) throws IOException {
 int port = 8888;
 ServerSocket serverSocket = new ServerSocket(port);
 System.out.println("Server waiting for client on port " + port);

 Socket clientSocket = serverSocket.accept();
 System.out.println("Client connected: " + clientSocket.getInetAddress());

 BufferedReader in = new BufferedReader(
 new InputStreamReader(clientSocket.getInputStream()));
 PrintWriter out = new PrintWriter(
 clientSocket.getOutputStream(), true);

 String message = in.readLine();
 System.out.println("Received: " + message);
 out.println("ECHO: " + message);

 in.close(); out.close(); clientSocket.close(); serverSocket.close();
 }
}

import java.io.*;
import java.net.*;

public class TCPClient {
 public static void main(String[] args) throws IOException {
 String serverIP = "localhost";
 int serverPort = 8888;

 Socket socket = new Socket(serverIP, serverPort);
 System.out.println("Connected to server");

 PrintWriter out = new PrintWriter(
 socket.getOutputStream(), true);
 BufferedReader in = new BufferedReader(
 new InputStreamReader(socket.getInputStream()));
 BufferedReader userInput = new BufferedReader(
 new InputStreamReader(System.in));

 System.out.print("Enter message: ");
 String message = userInput.readLine();
 out.println(message);

 String response = in.readLine();
 System.out.println("Server response: " + response);

 in.close(); out.close(); socket.close();
 }
}

import java.io.*;
import java.net.*;

public class UDPServer {
 public static void main(String[] args) throws IOException {
 int port = 9999;
 DatagramSocket socket = new DatagramSocket(port);
 System.out.println("UDP Server running on port " + port);

 byte[] buffer = new byte[1024];
 DatagramPacket packet = new DatagramPacket(buffer, buffer.length);

 socket.receive(packet);
 String message = new String(packet.getData(), 0, packet.getLength());
 System.out.println("Received: " + message);

 String response = "ECHO: " + message;
 DatagramPacket responsePacket = new DatagramPacket(
 response.getBytes(), response.length(),
 packet.getAddress(), packet.getPort());
 socket.send(responsePacket);

 socket.close();
 }
}

import java.io.*;
import java.net.*;

public class ConcurrentServer {
 public static void main(String[] args) throws IOException {
 int port = 8888;
 ServerSocket serverSocket = new ServerSocket(port);
 System.out.println("Concurrent Server started on port " + port);

 while (true) {
 Socket clientSocket = serverSocket.accept();
 System.out.println("New client: " + clientSocket.getInetAddress());
 // Create new thread for each client
 new ClientHandler(clientSocket).start();
 }
 }
}

class ClientHandler extends Thread {
 private Socket socket;

 public ClientHandler(Socket socket) {
 this.socket = socket;
 }

 public void run() {
 try {
 BufferedReader in = new BufferedReader(
 new InputStreamReader(socket.getInputStream()));
 PrintWriter out = new PrintWriter(
 socket.getOutputStream(), true);

 String message;
 while ((message = in.readLine()) != null) {
 out.println("ECHO: " + message);
 }
 socket.close();
 } catch (IOException e) {
 e.printStackTrace();
 }
 }
}

